Create the core route definition file at `apps/client/src/router.ts`. This file lives at the app level (not inside FSD layers) because routes are app-level orchestration.

**File: `apps/client/src/router.ts`**

```typescript
import { createRootRouteWithContext, createRoute, createRouter, Outlet, redirect } from '@tanstack/react-router';
import { QueryClient } from '@tanstack/react-query';
import { z } from 'zod';
import { zodValidator } from '@tanstack/zod-adapter';

// ── Router context ──────────────────────────────────────────
interface RouterContext {
  queryClient: QueryClient;
}

// ── Root route (minimal — just Outlet) ──────────────────────
const rootRoute = createRootRouteWithContext<RouterContext>()({
  component: () => <Outlet />,
  notFoundComponent: () => <div>404 — Page not found</div>,
});

// ── Pathless layout route (app shell) ───────────────────────
// Uses `id` not `path` — no URL segment added.
// Sidebar, header, dialogs, toaster render here.
import { AppShell } from './AppShell';

const appShellRoute = createRoute({
  getParentRoute: () => rootRoute,
  id: '_shell',
  component: AppShell,
});

// ── Search param schema ─────────────────────────────────────
const sessionSearchSchema = z.object({
  session: z.string().optional(),
  dir: z.string().optional(),
});

export type SessionSearch = z.infer<typeof sessionSearchSchema>;

// ── Dashboard at / ──────────────────────────────────────────
import { DashboardPage } from '@/layers/widgets/dashboard';

const indexRoute = createRoute({
  getParentRoute: () => appShellRoute,
  path: '/',
  component: DashboardPage,
  // Redirect to /session if ?session= param is present (backward compat for old bookmarks)
  beforeLoad: ({ search }) => {
    const params = new URLSearchParams(window.location.search);
    const session = params.get('session');
    if (session) {
      throw redirect({
        to: '/session',
        search: { session, dir: params.get('dir') ?? undefined },
      });
    }
  },
});

// ── Session/chat at /session ────────────────────────────────
import { SessionPage } from '@/layers/widgets/session';

const sessionRoute = createRoute({
  getParentRoute: () => appShellRoute,
  path: '/session',
  validateSearch: zodValidator(sessionSearchSchema),
  component: SessionPage,
});

// ── Route tree ──────────────────────────────────────────────
const routeTree = rootRoute.addChildren([
  appShellRoute.addChildren([indexRoute, sessionRoute]),
]);

// ── Router factory ──────────────────────────────────────────
export function createAppRouter(queryClient: QueryClient) {
  return createRouter({
    routeTree,
    context: { queryClient },
    defaultPreload: 'intent',
  });
}

// ── Type registration ───────────────────────────────────────
declare module '@tanstack/react-router' {
  interface Register {
    router: ReturnType<typeof createAppRouter>;
  }
}
```

**Key design decisions:**
- `createRootRouteWithContext` injects `QueryClient` into router context — enables route loaders to prefetch data for future dashboard content
- Pathless layout route (`id: '_shell'`) wraps shared UI without adding a URL segment — both `/` and `/session` share the shell
- `z.string().optional()` means `undefined` = absent from URL; TanStack Router omits the key entirely (clean URLs)
- `notFoundComponent` on root catches unrecognized routes
- `defaultPreload: 'intent'` fires loaders on hover/focus for instant navigation
- `beforeLoad` on the index route redirects `/?session=abc` to `/session?session=abc` for backward compatibility with old bookmarks

**Acceptance criteria:**
- File exists at `apps/client/src/router.ts`
- Exports `createAppRouter` function and `SessionSearch` type
- Route tree has three routes: root, index (`/`), session (`/session`)
- Session route validates search params with Zod via `zodValidator`
- Index route has a `beforeLoad` that redirects `/?session=x` to `/session?session=x`
- TypeScript module augmentation registers the router type
- `pnpm typecheck --filter=@dorkos/client` passes once AppShell, DashboardPage, and SessionPage exist

Create a shared helper hook that safely reads session route search params from any route. This is used by `useSessionId` and `useDirectoryState` to read `?session=` and `?dir=` without crashing when not on the session route.

**File: `apps/client/src/layers/entities/session/model/use-session-search.ts`**

```typescript
import { useSearch } from '@tanstack/react-router';
import type { SessionSearch } from '@/router';

/**
 * Read session search params safely from any route.
 *
 * Uses `strict: false` from the root route, returning only session-related
 * params. Returns empty object when the params are absent or not on the
 * session route.
 */
export function useSessionSearch(): Partial<SessionSearch> {
  try {
    return useSearch({ from: '/session' });
  } catch {
    // Not on session route — return empty
    return {};
  }
}
```

**Alternative consideration from spec (Open Question 1, RESOLVED):** The spec resolved that `useSearch({ from: '/session', strict: false })` returns `undefined` when not on the session route, handled by `?? null` fallback in hooks. During implementation, evaluate whether `strict: false` on the session route search or the try/catch approach is cleaner. The try/catch approach is the safer default.

